mapper.select:
SELECT i.*, d.drug_name AS drugName FROM inventory i INNER JOIN drug_info d ON i.drug_id = d.id WHERE i.quantity > 0 AND d.deleted = 0
AND (d.drug_name LIKE CONCAT('%', #{keyword}, '%') OR d.national_code LIKE CONCAT('%', #{keyword}, '%') OR d.approval_number LIKE CONCAT('%', #{keyword}, '%') OR i.batch_number LIKE CONCAT('%', #{keyword}, '%') OR i.storage_location LIKE CONCAT('%', #{keyword}, '%'))
AND i.drug_id = #{drugId}
AND i.batch_number LIKE CONCAT('%', #{batchNumber}, '%')
AND i.storage_location LIKE CONCAT('%', #{storageLocation}, '%')
AND i.expiry_date >= #{expiryDateStart}
AND i.expiry_date <= #{expiryDateEnd}
AND d.is_special = #{isSpecial}
ORDER BY i.expiry_date ASC, i.create_time DESC

SELECT i.*, d.drug_name AS drugName FROM inventory i INNER JOIN drug_info d ON i.drug_id = d.id WHERE i.quantity > 0 AND d.deleted = 0
AND i.expiry_date >= #{today} AND i.expiry_date <= #{redBoundary}
AND i.expiry_date > #{redBoundary} AND i.expiry_date <= #{yellowBoundary}
ORDER BY i.expiry_date ASC, i.batch_number ASC
